func writeGo(t *testing.T, src string) string {
	t.Helper()
	dir := t.TempDir()
	path := filepath.Join(dir, "foo.go")
	if err := os.WriteFile(path, []byte(src), 0644); err != nil {
		t.Fatal(err)
	}
	return path
}

func TestGenerateForFile_CreatesNewTestFile(t *testing.T) {
	src := `package example

func DoThing(x int) int { return x + 1 }

type Svc struct{}

func (s *Svc) Process() error { return nil }

// unexported 不該被產生
func helper() {}
`
	path := writeGo(t, src)
	rep, err := GenerateForFile(path, DefaultOptions())
	if err != nil {
		t.Fatal(err)
	}
	if !rep.Created {
		t.Error("expected test file to be created")
	}
	if len(rep.Added) != 2 {
		t.Errorf("Added = %v, want 2 (TestDoThing + TestSvc_Process)", rep.Added)
	}

	data, _ := os.ReadFile(rep.TestFile)
	out := string(data)
	if !strings.Contains(out, "package example") {
		t.Error("package declaration missing")
	}
	if !strings.Contains(out, "func TestDoThing(t *testing.T)") {
		t.Errorf("TestDoThing missing in:\n%s", out)
	}
	if !strings.Contains(out, "func TestSvc_Process(t *testing.T)") {
		t.Errorf("TestSvc_Process missing in:\n%s", out)
	}
	if strings.Contains(out, "TestHelper") || strings.Contains(out, "Testhelper") {
		t.Errorf("should not generate test for unexported helper:\n%s", out)
	}
	if !strings.Contains(out, "t.Skip") {
		t.Errorf("stub should call t.Skip:\n%s", out)
	}
}

