func TestGenerateForFile_SkipsExistingTest(t *testing.T) {
	src := `package example

func Foo() {}
func Bar() {}
`
	path := writeGo(t, src)
	testPath := strings.TrimSuffix(path, ".go") + "_test.go"
	existing := `package example

import "testing"

func TestFoo(t *testing.T) { /* hand-written */ }
`
	if err := os.WriteFile(testPath, []byte(existing), 0644); err != nil {
		t.Fatal(err)
	}

	rep, err := GenerateForFile(path, DefaultOptions())
	if err != nil {
		t.Fatal(err)
	}
	if rep.Created {
		t.Error("test file already exists; Created should be false")
	}
	if len(rep.Skipped) != 1 || rep.Skipped[0] != "TestFoo" {
		t.Errorf("Skipped = %v, want [TestFoo]", rep.Skipped)
	}
	if len(rep.Added) != 1 || rep.Added[0] != "TestBar" {
		t.Errorf("Added = %v, want [TestBar]", rep.Added)
	}

	// 既有 TestFoo 應該不變
	data, _ := os.ReadFile(testPath)
	out := string(data)
	if !strings.Contains(out, "hand-written") {
		t.Error("existing TestFoo content should be preserved")
	}
	if !strings.Contains(out, "func TestBar(t *testing.T)") {
		t.Errorf("TestBar should be appended:\n%s", out)
	}
}

