func TestGenerateForFile_DryRunDoesNotWrite(t *testing.T) {
	src := `package example
func DoThing() {}
`
	path := writeGo(t, src)
	opts := DefaultOptions()
	opts.DryRun = true

	rep, err := GenerateForFile(path, opts)
	if err != nil {
		t.Fatal(err)
	}
	if len(rep.Added) != 1 {
		t.Errorf("dry run should still report what WOULD be added")
	}
	if _, err := os.Stat(rep.TestFile); err == nil {
		t.Error("dry run should NOT create the test file")
	}
}

