func TestGenerateForDir_RecursesAndSkipsCommonDirs(t *testing.T) {
	root := t.TempDir()
	mkfile := func(rel, content string) {
		full := filepath.Join(root, rel)
		os.MkdirAll(filepath.Dir(full), 0755)
		os.WriteFile(full, []byte(content), 0644)
	}
	mkfile("a.go", "package x\nfunc Alpha() {}\n")
	mkfile("sub/b.go", "package y\nfunc Beta() {}\n")
	mkfile("vendor/v.go", "package v\nfunc Vend() {}\n") // 應跳過
	mkfile(".hyp/h.go", "package h\nfunc H() {}\n")     // 應跳過
	mkfile("testdata/t.go", "package t\nfunc T() {}\n") // 應跳過

	reports, err := GenerateForDir(root, DefaultOptions())
	if err != nil {
		t.Fatal(err)
	}

	created := map[string]bool{}
	for _, r := range reports {
		if r.Created {
			rel, _ := filepath.Rel(root, r.TestFile)
			created[filepath.ToSlash(rel)] = true
		}
	}
	if !created["a_test.go"] {
		t.Error("a_test.go should be created")
	}
	if !created["sub/b_test.go"] {
		t.Error("sub/b_test.go should be created")
	}
	if created["vendor/v_test.go"] {
		t.Error("vendor/ should be skipped")
	}
	if created[".hyp/h_test.go"] {
		t.Error(".hyp/ should be skipped")
	}
	if created["testdata/t_test.go"] {
		t.Error("testdata/ should be skipped")
	}
}

func TestIsReservedTestPrefix(t *testing.T) {
	for _, name := range []string{"TestFoo", "BenchmarkBar", "ExampleBaz", "FuzzQux"} {
		if !isReservedTestPrefix(name) {
			t.Errorf("%q should be reserved", name)
		}
	}
	for _, name := range []string{"Foo", "BarTest", "TestlikeNotTest"} {
		if isReservedTestPrefix(name) {
			t.Errorf("%q should NOT be reserved", name)
		}
	}
}
